<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/comunicacion_layout.php';$pdo=obtenerConexion();$actor=(int)$_SESSION['usuario_id'];$id=filter_var($_GET['id']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$yo=comunicacionUsuario($pdo,$actor);$q=$pdo->prepare('SELECT h.* FROM correo_centro_hilos h WHERE h.id=:h AND (:admin=1 OR EXISTS(SELECT 1 FROM correo_centro_mensajes m WHERE m.hilo_id=h.id AND (m.autor_usuario_id=:u OR h.usuario_relacionado_id=:u2 OR m.destinatario=:c OR m.remitente=:c2)))');$q->execute(['h'=>$id,'admin'=>$_SESSION['usuario_rol']==='admin'?1:0,'u'=>$actor,'u2'=>$actor,'c'=>$yo['correo'],'c2'=>$yo['correo']]);$h=$q->fetch();if(!$h){http_response_code(403);exit('Hilo no autorizado.');}$pdo->prepare("UPDATE correo_centro_mensajes SET leido_at=COALESCE(leido_at,NOW()) WHERE hilo_id=:h AND direccion='entrada'")->execute(['h'=>$id]);$q=$pdo->prepare('SELECT m.*,(SELECT GROUP_CONCAT(a.id) FROM correo_centro_adjuntos a WHERE a.mensaje_id=m.id) adjuntos FROM correo_centro_mensajes m WHERE m.hilo_id=:h ORDER BY m.enviado_recibido_at,m.id');$q->execute(['h'=>$id]);$mensajes=$q->fetchAll();comunicacionCabecera($h['asunto'],'entrada','Hilo de correo institucional.');comunicacionNav('entrada');?>
<div class="card card-rounded"><div class="card-body"><?php foreach($mensajes as$m):?><article class="border rounded p-3 mb-3"><strong><?=atenea_e($m['remitente'])?> → <?=atenea_e($m['destinatario'])?></strong><span class="badge bg-secondary float-end"><?=atenea_e($m['estado'])?></span><p style="white-space:pre-wrap" class="mt-3"><?=atenea_e($m['contenido_texto'])?></p><?php foreach(array_filter(explode(',',(string)$m['adjuntos'])) as$aid):?><a class="btn btn-sm btn-outline-secondary me-1" href="archivo.php?id=<?=(int)$aid?>">Descargar adjunto</a><?php endforeach;?><small class="d-block mt-2"><?=atenea_e($m['enviado_recibido_at'])?></small></article><?php endforeach;?><a class="btn btn-primary" href="redactar.php?hilo=<?=$id?>&destinatario=<?=(int)$h['usuario_relacionado_id']?>">Responder</a></div></div><?php comunicacionPie();
